import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicEight() {
        // [10,9,2,5,3,7,101,18]: LIS length 4 e.g. [2,3,7,101]
        assertEquals(4, new Solution().lengthOfLIS(new int[]{10, 9, 2, 5, 3, 7, 101, 18}));
    }

    @Test
    void classicSix() {
        // [0,1,0,3,2,3]: LIS length 4 e.g. [0,1,2,3]
        assertEquals(4, new Solution().lengthOfLIS(new int[]{0, 1, 0, 3, 2, 3}));
    }

    @Test
    void allEqual() {
        // [7,7,7,7]: strictly increasing â€” no extension possible, LIS = 1
        assertEquals(1, new Solution().lengthOfLIS(new int[]{7, 7, 7, 7}));
    }

    @Test
    void singleElement() {
        assertEquals(1, new Solution().lengthOfLIS(new int[]{1}));
    }

    @Test
    void emptyArray() {
        assertEquals(0, new Solution().lengthOfLIS(new int[]{}));
    }

    @Test
    void alreadySorted() {
        // [1,2,3,4,5]: entire array is the LIS
        assertEquals(5, new Solution().lengthOfLIS(new int[]{1, 2, 3, 4, 5}));
    }

    @Test
    void strictlyDecreasing() {
        // [5,4,3,2,1]: every element is its own LIS of length 1
        assertEquals(1, new Solution().lengthOfLIS(new int[]{5, 4, 3, 2, 1}));
    }
}
